import{_ as o,a,b as n,c as t,d,e as i,f as r,g as s}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as u,c as p,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Federovaný distribuovaný index","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/federated-distributed-index.md","filePath":"cs-CZ/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),c={name:"cs-CZ/Other/federated-distributed-index.md"};function v(z,e,m,k,b,y){return u(),p("div",null,[...e[0]||(e[0]=[h('<h1 id="federovany-distribuovany-index" tabindex="-1">Federovaný distribuovaný index <a class="header-anchor" href="#federovany-distribuovany-index" aria-label="Permalink to &quot;Federovaný distribuovaný index&quot;">​</a></h1><p>Federovaný distribuovaný index umožňuje více webům ImgBed sdílet mezi sebou seznamy souborů.</p><p>Jednoduše:</p><ul><li>Můžete sdílet vybrané adresáře ze svého webu s ostatními.</li><li>Můžete se připojit k jinému uzlu a synchronizovat jeho sdílený seznam souborů do své administrace.</li><li>Federované soubory slouží hlavně k procházení, vyhledávání a otevírání odkazů. Nenahrávají se znovu do vašeho úložiště.</li></ul><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Otevřete:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+o+`" alt="Místní federovaný uzel" loading="lazy"></p><p>Stránka má tři karty:</p><table tabindex="0"><thead><tr><th>Karta</th><th>Účel</th></tr></thead><tbody><tr><td>Local Node</td><td>Zapnout vlastní uzel, potvrdit veřejnou doménu, vybrat sdílené adresáře a aktualizovat odchozí index</td></tr><tr><td>Nodes I Joined</td><td>Spravovat jiné uzly ImgBed, ke kterým jste se připojili</td></tr><tr><td>Nodes Joining Me</td><td>Spravovat žádosti ostatních, kteří se chtějí připojit k vašemu uzlu</td></tr></tbody></table><h2 id="prvni-nastaveni" tabindex="-1">První nastavení <a class="header-anchor" href="#prvni-nastaveni" aria-label="Permalink to &quot;První nastavení&quot;">​</a></h2><ol><li>Otevřete <code>Local Node</code>.</li><li>Zapněte <code>Enable</code>.</li><li>V <code>Sync folders</code> vyberte adresáře ke sdílení.</li><li>Klikněte na <code>Update Outbound Index</code>.</li><li>Pokud ImgBed zjistí změnu domény, před pokračováním potvrďte, že aktuální doména je správná.</li></ol><p>Můžete vybrat více synchronizovaných adresářů.</p><p>Pokud je seznam synchronizovaných adresářů prázdný, sdílí se všechny adresáře.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="verejna-domena" tabindex="-1">Veřejná doména <a class="header-anchor" href="#verejna-domena" aria-label="Permalink to &quot;Veřejná doména&quot;">​</a></h3><p>Veřejná doména je URL webu, který ostatní uzly používají pro přístup k vašemu uzlu.</p><p>ImgBed ji zjistí automaticky. Nemusíte ji psát ručně. Při první aktualizaci indexu se ImgBed zeptá, zda je aktuální přístupový URL produkční doména.</p><p>Pokud později doménu změníte, aktualizace indexu se znovu zeptá na potvrzení.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders určují, které soubory se sdílejí s federovanými uzly.</p><p>Pokud například vyberete jen:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>ostatní uzly uvidí pouze soubory v těchto dvou adresářích.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Aktualizuje seznam souborů, který od vás mohou ostatní uzly synchronizovat.</p><p>Použijte, když:</p><ul><li>poprvé zapínáte federaci.</li><li>nahrajete soubory, které chcete sdílet.</li><li>změníte synchronizované adresáře.</li><li>změníte veřejnou doménu a je potřeba ji potvrdit.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> slouží ke správě připojení k jiným uzlům.</p><p><img src="`+a+'" alt="Uzly, ke kterým jsem se připojil" loading="lazy"></p><h3 id="zadost-o-pripojeni-k-jinemu-uzlu" tabindex="-1">Žádost o připojení k jinému uzlu <a class="header-anchor" href="#zadost-o-pripojeni-k-jinemu-uzlu" aria-label="Permalink to &quot;Žádost o připojení k jinému uzlu&quot;">​</a></h3><ol><li>Požádejte druhého vlastníka o pozvánkový odkaz.</li><li>Vložte ho do vstupního pole.</li><li>Klikněte na <code>Request to Join</code>.</li><li>Počkejte, až druhý vlastník žádost schválí ve své administraci.</li></ol><p>Po schválení se stav uzlu změní na approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> synchronizuje seznamy souborů z uzlů, ke kterým jste se připojili.</p><p>Použijte, když:</p><ul><li>druhý vlastník právě schválil vaši žádost.</li><li>druhý vlastník oznámí, že sdílený obsah byl aktualizován.</li><li>chcete obnovit všechny připojené federované seznamy souborů.</li></ul><p>Pro aktualizaci jen jednoho uzlu klikněte na <code>Update Index</code> na jeho kartě.</p><p><img src="'+n+'" alt="Aktualizace indexu" loading="lazy"></p><h3 id="odhlaseni" tabindex="-1">Odhlášení <a class="header-anchor" href="#odhlaseni" aria-label="Permalink to &quot;Odhlášení&quot;">​</a></h3><p>Pokud už nechcete uzel synchronizovat, klikněte na <code>Unsubscribe</code>.</p><p>Po odhlášení se federovaný index tohoto uzlu odstraní z vašeho místního webu.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> slouží ke zpracování žádostí od ostatních.</p><p><img src="'+t+'" alt="Uzly připojující se ke mně" loading="lazy"></p><h3 id="vygenerovani-pozvankoveho-odkazu" tabindex="-1">Vygenerování pozvánkového odkazu <a class="header-anchor" href="#vygenerovani-pozvankoveho-odkazu" aria-label="Permalink to &quot;Vygenerování pozvánkového odkazu&quot;">​</a></h3><ol><li>Ujistěte se, že místní uzel je zapnutý.</li><li>Klikněte alespoň jednou na <code>Update Outbound Index</code>, aby ImgBed potvrdil veřejnou doménu.</li><li>Otevřete <code>Nodes Joining Me</code>.</li><li>Klikněte na <code>Reset Invitation Link</code>.</li><li>Zkopírujte pozvánkový odkaz a pošlete ho druhému vlastníkovi.</li></ol><p>Pokud je pozvánkový odkaz prázdný, veřejná doména obvykle ještě nebyla potvrzená. Vraťte se do <code>Local Node</code> a klikněte na <code>Update Outbound Index</code>.</p><h3 id="zpracovani-zadosti-o-pripojeni" tabindex="-1">Zpracování žádostí o připojení <a class="header-anchor" href="#zpracovani-zadosti-o-pripojeni" aria-label="Permalink to &quot;Zpracování žádostí o připojení&quot;">​</a></h3><p>Když někdo odešle žádost, objeví se v seznamu <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Akce</th><th>Význam</th></tr></thead><tbody><tr><td>Approve</td><td>Umožní druhému uzlu synchronizovat váš sdílený seznam souborů</td></tr><tr><td>Reject</td><td>Odmítne žádost</td></tr><tr><td>Delete</td><td>Odstraní dokončený záznam</td></tr><tr><td>Check Status</td><td>Zkontroluje, zda druhá strana stále udržuje tento vztah</td></tr></tbody></table><p>Po schválení musí druhá strana ještě kliknout na <code>Update Inbound Index</code>, než se tam vaše sdílené soubory zobrazí.</p><p><img src="'+d+'" alt="Schválení pozvaného uzlu" loading="lazy"></p><h2 id="zpravy" tabindex="-1">Zprávy <a class="header-anchor" href="#zpravy" aria-label="Permalink to &quot;Zprávy&quot;">​</a></h2><p>Po schválení vztahu klikněte na kartě uzlu na <code>Message</code>.</p><p>Zprávy slouží jen pro komunikaci o federovaném vztahu. Nemění soubory, tagy, adresáře ani oprávnění.</p><p><img src="'+i+'" alt="Zprávy" loading="lazy"></p><h2 id="prohlizeni-federovanych-souboru" tabindex="-1">Prohlížení federovaných souborů <a class="header-anchor" href="#prohlizeni-federovanych-souboru" aria-label="Permalink to &quot;Prohlížení federovaných souborů&quot;">​</a></h2><p>Po dokončení synchronizace se vraťte do seznamu souborů v administraci.</p><p>V horní části stránky můžete přepínat mezi místními soubory a federovanými soubory. Ve federovaných souborech lze procházet synchronizovaný obsah.</p><p>Federované soubory slouží hlavně k prohlížení, vyhledávání, náhledu a kopírování odkazů. Nejsou to místní soubory, takže je z vlastního webu nemůžete přesouvat, mazat, znovu tagovat ani zálohovat.</p><p><img src="'+r+'" alt="Federované soubory v administraci" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="proc-me-to-zada-o-novou-zadost-protoze-neexistuje-zaznam-vztahu" tabindex="-1">Proč mě to žádá o novou žádost, protože neexistuje záznam vztahu? <a class="header-anchor" href="#proc-me-to-zada-o-novou-zadost-protoze-neexistuje-zaznam-vztahu" aria-label="Permalink to &quot;Proč mě to žádá o novou žádost, protože neexistuje záznam vztahu?&quot;">​</a></h3><p>Obvykle to znamená, že vás druhá strana odstranila a záznam smazala, takže vztah už nelze najít. Odešlete novou žádost o připojení.</p><p><img src="'+s+'" alt="Nová žádost bez záznamu vztahu" loading="lazy"></p><h3 id="proc-po-pripojeni-nevidim-soubory" tabindex="-1">Proč po připojení nevidím soubory? <a class="header-anchor" href="#proc-po-pripojeni-nevidim-soubory" aria-label="Permalink to &quot;Proč po připojení nevidím soubory?&quot;">​</a></h3><p>Zkontrolujte:</p><ol><li>Druhý vlastník vaši žádost schválil.</li><li>Druhý vlastník klikl na <code>Update Outbound Index</code>.</li><li>Vy jste klikli na <code>Update Inbound Index</code>.</li><li>Synchronizované adresáře druhého vlastníka obsahují adresáře, které chce sdílet.</li></ol><h3 id="co-delat-pri-zjisteni-zmeny-domeny" tabindex="-1">Co dělat při zjištění změny domény? <a class="header-anchor" href="#co-delat-pri-zjisteni-zmeny-domeny" aria-label="Permalink to &quot;Co dělat při zjištění změny domény?&quot;">​</a></h3><p>Pokud administraci právě otevíráte přes produkční doménu, potvrďte a pokračujte.</p><p>Pokud používáte dočasnou adresu, zrušte akci, otevřete administraci přes produkční doménu a zkuste to znovu.</p><h3 id="co-znamena-prazdny-seznam-sync-folder" tabindex="-1">Co znamená prázdný seznam Sync Folder? <a class="header-anchor" href="#co-znamena-prazdny-seznam-sync-folder" aria-label="Permalink to &quot;Co znamená prázdný seznam Sync Folder?&quot;">​</a></h3><p>Prázdný seznam Sync Folder znamená, že se sdílejí všechny adresáře.</p><p>Pokud chcete sdílet jen některé adresáře, vyberte je ručně.</p><h3 id="rozdil-mezi-odchozi-a-prichozi-aktualizaci-indexu" tabindex="-1">Rozdíl mezi odchozí a příchozí aktualizací indexu <a class="header-anchor" href="#rozdil-mezi-odchozi-a-prichozi-aktualizaci-indexu" aria-label="Permalink to &quot;Rozdíl mezi odchozí a příchozí aktualizací indexu&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tlačítko</th><th>Jednoduchý význam</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Aktualizuje, co ode mě mohou ostatní synchronizovat</td></tr><tr><td>Update Inbound Index</td><td>Aktualizuje, co jsem synchronizoval od ostatních</td></tr></tbody></table>',78)])])}const g=l(c,[["render",v]]);export{f as __pageData,g as default};
